select from appointment_record a left join doctor_info d on a.doctor_id = d.id left join department_info dp on a.department_id = dp.id left join medical_card c on a.card_id = c.id left join payment_order o on a.order_id = o.id
and (a.appointment_no like concat('%', #{keyword}, '%') or a.patient_name like concat('%', #{keyword}, '%') or d.doctor_name like concat('%', #{keyword}, '%'))
and a.status = #{status}
and a.doctor_id = #{doctorId}
and a.department_id = #{departmentId}
order by a.id desc

